if (!defined('ABSPATH')) exit;

function mpd_get_int_from_get($key, $default = 0) {
	if (!isset($_GET[$key])) return (int)$default;
	$val = wp_unslash($_GET[$key]);
	if (is_array($val)) return (int)$default;
	return (int)$val;
}

function mpd_render_user_profile_by_url_param() {
	if (!is_user_logged_in()) {
		return '<div class="mpd-profile mpd-error">You must be logged in to view profiles.</div>';
	}

	$user_id = mpd_get_int_from_get('user_id', 0);
	if ($user_id <= 0) {
		return '<div class="mpd-profile mpd-error">Missing or invalid user_id.</div>';
	}

	global $wpdb;

	$users_table = $wpdb->prefix . 'users';
	$usermeta_table = $wpdb->prefix . 'usermeta';

	$user = $wpdb->get_row(
		$wpdb->prepare(
			"SELECT ID, user_login, user_nicename, user_email, user_url, user_registered, display_name
			 FROM {$users_table}
			 WHERE ID = %d
			 LIMIT 1",
			$user_id
		),
		ARRAY_A
	);

	if (!$user) {
		return '<div class="mpd-profile mpd-error">User not found.</div>';
	}

	$meta_keys = array(
		'first_name',
		'last_name',
		'nickname',
		'description',
	);

	$placeholders = implode(',', array_fill(0, count($meta_keys), '%s'));
	$params = $meta_keys;
	array_unshift($params, $user_id);

	$meta_rows = $wpdb->get_results(
		$wpdb->prepare(
			"SELECT meta_key, meta_value
			 FROM {$usermeta_table}
			 WHERE user_id = %d
			   AND meta_key IN ({$placeholders})",
			$params
		),
		ARRAY_A
	);

	$meta = array();
	foreach ($meta_rows as $row) {
		$meta[$row['meta_key']] = maybe_unserialize($row['meta_value']);
	}

	$display_name = $user['display_name'];
	if (empty($display_name)) {
		$fn = isset($meta['first_name']) ? (string)$meta['first_name'] : '';
		$ln = isset($meta['last_name']) ? (string)$meta['last_name'] : '';
		$display_name = trim($fn . ' ' . $ln);
		if ($display_name === '') $display_name = $user['user_login'];
	}

	$avatar = get_avatar($user_id, 96);

	$out  = '<div class="mpd-profile">';
	$out .= '<div class="mpd-profile-header">';
	$out .= '<div class="mpd-profile-avatar">' . $avatar . '</div>';
	$out .= '<div class="mpd-profile-title">';
	$out .= '<h2 class="mpd-profile-name">' . esc_html($display_name) . '</h2>';
	$out .= '<div class="mpd-profile-username">@' . esc_html($user['user_login']) . '</div>';
	$out .= '</div>';
	$out .= '</div>';

	$out .= '<div class="mpd-profile-body">';
	$out .= '<ul class="mpd-profile-fields">';

	$out .= '<li><strong>Member Since:</strong> ' . esc_html(mysql2date(get_option('date_format'), $user['user_registered'])) . '</li>';

	if (!empty($meta['nickname'])) {
		$out .= '<li><strong>Nickname:</strong> ' . esc_html((string)$meta['nickname']) . '</li>';
	}

	if (!empty($meta['first_name']) || !empty($meta['last_name'])) {
		$out .= '<li><strong>Name:</strong> ' . esc_html(trim((string)($meta['first_name'] ?? '') . ' ' . (string)($meta['last_name'] ?? ''))) . '</li>';
	}

	if (!empty($meta['description'])) {
		$out .= '<li><strong>Bio:</strong> ' . wp_kses_post(wpautop((string)$meta['description'])) . '</li>';
	}

	$out .= '</ul>';
	$out .= '</div>';

	$out .= '</div>';

	return $out;
}

